"use client";
import { useState } from 'react';

const API_URL = 'http://localhost:8081';

export default function Home() {
  const [view, setView] = useState<'login' | 'register' | 'dashboard'>('login');
  const [email, setEmail] = useState('test@example.com');
  const [password, setPassword] = useState('Password123!');
  const [loading, setLoading] = useState(false);
  const [logs, setLogs] = useState<string[]>([]);
  const [user, setUser] = useState<any>(null);

  const addLog = (msg: string) => setLogs(prev => [`[${new Date().toLocaleTimeString()}] ${msg}`, ...prev]);

  async function handleAuth(endpoint: string) {
    setLoading(true);
    addLog(`Sending ${endpoint} request...`);
    try {
      const res = await fetch(`${API_URL}/auth/${endpoint}`, {
        method: 'POST',
        body: JSON.stringify({ email, password }),
      });
      const data = await res.json();
      
      if (res.ok) {
        addLog(`✅ ${endpoint} Successful!`);
        if (endpoint === 'login') {
            setUser({ email });
            setView('dashboard');
        } else {
            alert('Account created! Please login.');
            setView('login');
        }
      } else {
        addLog(`❌ Error: ${data.message}`);
        alert(data.message);
      }
    } catch (e) {
      addLog(`❌ Network Error: ${e}`);
    } finally {
      setLoading(false);
    }
  }

  async function checkUser() {
    try {
        const res = await fetch(`${API_URL}/auth/user`);
        const data = await res.json();
        if(res.ok) addLog(`👤 User ID: ${data.id}`);
        else addLog(`⚠️ ${data.message}`);
    } catch(e) { addLog(`${e}`) }
  }

  async function logout() {
    await fetch(`${API_URL}/auth/logout`, { method: 'POST' });
    setUser(null);
    setView('login');
    addLog('👋 Logged out');
  }

  return (
    <main className="min-h-screen bg-black text-white flex flex-col items-center justify-center p-4 relative overflow-hidden font-sans">
      {/* Background Effects */}
      <div className="absolute top-[-20%] left-[-10%] w-[500px] h-[500px] bg-purple-600/30 rounded-full blur-[100px]" />
      <div className="absolute bottom-[-20%] right-[-10%] w-[500px] h-[500px] bg-blue-600/30 rounded-full blur-[100px]" />

      <div className="z-10 w-full max-w-md">
        <h1 className="text-4xl font-bold text-center mb-8 bg-gradient-to-r from-purple-400 to-blue-400 bg-clip-text text-transparent">
          Cognito<span className="text-white">Stream</span>
        </h1>

        {/* Card */}
        <div className="backdrop-blur-xl bg-white/5 border border-white/10 rounded-2xl p-8 shadow-2xl">
          
          {view === 'dashboard' ? (
            <div className="space-y-6 animate-in fade-in zoom-in duration-300">
               <div className="text-center">
                  <div className="text-6xl mb-2">🎉</div>
                  <h2 className="text-2xl font-bold">Welcome Back!</h2>
                  <p className="text-gray-400">{user?.email}</p>
               </div>
               
               <div className="bg-green-500/10 border border-green-500/20 p-4 rounded-lg flex items-center gap-3">
                  <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"/>
                  <span className="text-green-400 text-sm font-medium">Backend Connected</span>
               </div>

               <div className="grid grid-cols-2 gap-4">
                  <button onClick={checkUser} className="p-3 bg-white/5 hover:bg-white/10 rounded-lg text-sm transition font-medium border border-white/5">
                     Check Session
                  </button>
                  <button onClick={logout} className="p-3 bg-red-500/10 hover:bg-red-500/20 text-red-400 rounded-lg text-sm transition font-medium border border-red-500/10">
                     Sign Out
                  </button>
               </div>
            </div>
          ) : (
            <div className="space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-300">
              <div className="space-y-1">
                <label className="text-xs font-medium text-gray-400 uppercase tracking-wider ml-1">Email</label>
                <input 
                  type="email" 
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition text-white placeholder-gray-600"
                />
              </div>
              
              <div className="space-y-1">
                 <label className="text-xs font-medium text-gray-400 uppercase tracking-wider ml-1">Password</label>
                 <input 
                   type="password" 
                   value={password}
                   onChange={e => setPassword(e.target.value)}
                   className="w-full bg-black/20 border border-white/10 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition text-white placeholder-gray-600"
                 />
              </div>

              <button 
                onClick={() => handleAuth(view)}
                disabled={loading}
                className="w-full bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-500 hover:to-purple-500 text-white font-bold py-3 rounded-xl shadow-lg shadow-blue-500/25 transition transform active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed mt-4"
              >
                {loading ? 'Processing...' : (view === 'login' ? 'Sign In' : 'Create Account')}
              </button>

              <div className="text-center pt-2">
                <button 
                  onClick={() => setView(view === 'login' ? 'register' : 'login')}
                  className="text-sm text-gray-400 hover:text-white transition"
                >
                  {view === 'login' ? "Don't have an account? Sign Up" : "Already have an account? Sign In"}
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Logs */}
        <div className="mt-8 bg-black/40 backdrop-blur-md rounded-xl p-4 h-32 overflow-y-auto border border-white/5 font-mono text-xs text-gray-400">
           {logs.length === 0 && <div className="text-center opacity-50 italic pt-8">Activity logs will appear here...</div>}
           {logs.map((log, i) => (
             <div key={i} className="mb-1 border-l-2 border-blue-500/30 pl-2">{log}</div>
           ))}
        </div>
      </div>
    </main>
  );
}
